"use client";

import { Tabs as TabsRoot, type TabsProps } from "./tabs";
import { TabsList, type TabsListProps } from "./tabs-list";
import { TabsTrigger, type TabsTriggerProps } from "./tabs-trigger";
import { TabsContent, type TabsContentProps } from "./tabs-content";
import { useTabsContext, type TabsContextValue } from "./tabs-context";

const Tabs = Object.assign(TabsRoot, {
  List: TabsList,
  Trigger: TabsTrigger,
  Content: TabsContent,
});

export { Tabs, type TabsProps };
export { TabsList, type TabsListProps };
export { TabsTrigger, type TabsTriggerProps };
export { TabsContent, type TabsContentProps };
export { useTabsContext, type TabsContextValue };

"use client";

import {
  Children,
  isValidElement,
  type HTMLAttributes,
  type ReactNode,
  type Ref,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import type { SegmentedSize, SegmentedVariant } from "@/lib/segmented-variants";
import { cn } from "@/lib/utils";
import { TabsContext } from "./tabs-context";
import { TabsContent } from "./tabs-content";
import { TabsTrigger } from "./tabs-trigger";

export interface TabsProps<TValue extends string = string>
  extends Omit<HTMLAttributes<HTMLDivElement>, "defaultValue" | "onChange"> {
  value?: TValue;
  onChange?: (value: TValue) => void;
  defaultValue?: TValue;
  orientation?: "horizontal" | "vertical";
  /**
   * Visual variant. Tabs shares its segmented chrome with `ToggleGroup` via the
   * `segmentedItemVariants` / `segmentedContainerVariants` CVA module.
   *   - `underline` — gapped row with a foreground underline on the active tab (default).
   *   - `default`   — bordered button row; active = inverted block.
   *   - `bracket`   — frameless, active tab wears `[ … ]` markers.
   *   - `pill`      — joined track with a single sliding indicator. Horizontal-only:
   *                   the shared sliding indicator slides along `left`/`width`, so
   *                   pairing `variant="pill"` with `orientation="vertical"` leaves
   *                   the indicator pinned to the top of the track.
   */
  variant?: SegmentedVariant;
  size?: SegmentedSize;
  activationMode?: "automatic" | "manual";
  ref?: Ref<HTMLDivElement>;
}

interface TabTriggerElementProps {
  value?: string;
  disabled?: boolean;
  children?: ReactNode;
}

interface TabMetadata {
  enabledValues: string[];
  panelValues: string[];
  triggerValues: string[];
}

function collectTabMetadata(children: ReactNode): TabMetadata {
  const metadata: TabMetadata = {
    enabledValues: [],
    panelValues: [],
    triggerValues: [],
  };

  Children.forEach(children, (child) => {
    if (!isValidElement<TabTriggerElementProps>(child)) return;
    if (child.type === TabsRoot) return;

    if (child.type === TabsTrigger && typeof child.props.value === "string") {
      metadata.triggerValues.push(child.props.value);
      if (!child.props.disabled) metadata.enabledValues.push(child.props.value);
      return;
    }

    if (child.type === TabsContent && typeof child.props.value === "string") {
      metadata.panelValues.push(child.props.value);
    }

    const childMetadata = collectTabMetadata(child.props.children);
    metadata.enabledValues.push(...childMetadata.enabledValues);
    metadata.panelValues.push(...childMetadata.panelValues);
    metadata.triggerValues.push(...childMetadata.triggerValues);
  });

  return metadata;
}

/**
 * Tabbed view root. Renders `TabsList` (triggers) and `TabsContent` (panels)
 * with ARIA `tablist` / `tab` / `tabpanel` roles wired automatically.
 *
 * `activationMode="manual"` decouples focus from selection so arrow keys move
 * focus across triggers without switching the visible panel until Enter or
 * Space is pressed — useful when panel content is expensive to mount.
 *
 * @example
 * ```tsx
 * <Tabs defaultValue="preview">
 *   <TabsList>
 *     <TabsTrigger value="preview">Preview</TabsTrigger>
 *     <TabsTrigger value="code">Code</TabsTrigger>
 *     <TabsTrigger value="tests">Tests</TabsTrigger>
 *   </TabsList>
 *   <TabsContent value="preview"><ComponentPreview /></TabsContent>
 *   <TabsContent value="code"><CodeBlock language="tsx" /></TabsContent>
 *   <TabsContent value="tests"><TestReport /></TabsContent>
 * </Tabs>
 * ```
 *
 * @example
 * ```tsx
 * const [tab, setTab] = useState("preview");
 * <Tabs value={tab} onChange={setTab} activationMode="manual">...</Tabs>
 * ```
 */
function TabsRoot<TValue extends string = string>({
  value: controlledValue,
  onChange,
  defaultValue,
  orientation = "horizontal",
  variant = "underline",
  size = "sm",
  activationMode = "automatic",
  children,
  className,
  ref,
  ...rest
}: TabsProps<TValue>) {
  const tabsId = useId();
  const { enabledValues, panelValues, triggerValues } = useMemo(() => collectTabMetadata(children), [children]);
  const [value, setValue] = useControllableState<string>({
    value: controlledValue,
    defaultValue: defaultValue ?? "",
    // TValue is a string subtype; downstream context uses string for runtime DOM matching.
    onChange: onChange as ((value: string) => void) | undefined,
  });
  const [focusedValue, setFocusedValue] = useState<string | null>(null);
  const hasWarnedNoTriggersRef = useRef(false);
  if (triggerValues.length === 0 && !defaultValue && !hasWarnedNoTriggersRef.current) {
    hasWarnedNoTriggersRef.current = true;
    console.warn(
      "[Tabs] No Tabs.Trigger children detected. Provide at least one Tabs.Trigger or set defaultValue to support lazy-loaded triggers.",
    );
  }
  const firstEnabledTab = enabledValues[0] ?? "";
  const resolvedValue = enabledValues.includes(value) ? value : firstEnabledTab;
  const resolvedFocusedValue = focusedValue !== null && enabledValues.includes(focusedValue)
    ? focusedValue
    : resolvedValue;

  const contextValue = useMemo(
    () => ({
      tabsId,
      value: resolvedValue,
      tabbableValue: activationMode === "manual" ? resolvedFocusedValue : resolvedValue,
      onChange: setValue,
      onFocusChange: setFocusedValue,
      panelValues,
      triggerValues,
      orientation,
      variant,
      size,
      activationMode,
    }),
    [tabsId, resolvedValue, resolvedFocusedValue, activationMode, setValue, panelValues, triggerValues, orientation, variant, size],
  );

  return (
    <TabsContext value={contextValue}>
      <div
        ref={ref}
        className={cn("flex flex-col", className)}
        data-orientation={orientation}
        {...rest}
      >
        {children}
      </div>
    </TabsContext>
  );
}

export { TabsRoot as Tabs };

"use client";

import { useRef, type FocusEvent, type HTMLAttributes, type KeyboardEvent, type Ref } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { useNavigation } from "@/hooks/use-navigation";
import { useFloatingIndicator } from "@/hooks/use-floating-indicator";
import {
  segmentedContainerVariants,
  segmentedPillIndicatorClass,
  segmentedUnderlineIndicatorClass,
} from "@/lib/segmented-variants";
import { cn } from "@/lib/utils";
import { useTabsContext } from "./tabs-context";

export interface TabsListProps extends HTMLAttributes<HTMLDivElement> {
  loop?: boolean;
  ref?: Ref<HTMLDivElement>;
}

export function TabsList({ children, className, loop = true, onBlur, onKeyDown, ref, ...rest }: TabsListProps) {
  const { orientation, variant, value, tabbableValue, onChange, onFocusChange, activationMode } = useTabsContext();

  const containerRef = useRef<HTMLDivElement>(null);

  const handleHighlightChange = (next: string | null) => {
    if (next === null) return;
    if (activationMode === "automatic") onChange(next);
    else onFocusChange(next);
  };

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "tab",
    orientation,
    wrap: loop,
    moveFocus: true,
    scopeToContainer: true,
    highlighted: (activationMode === "automatic" ? value : tabbableValue) || undefined,
    onHighlightChange: handleHighlightChange,
    ...(activationMode !== "automatic" && {
      onEnter: onChange,
      onSelect: onChange,
    }),
  });

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented) navKeyDown(e);
  };

  const handleBlur = (event: FocusEvent<HTMLDivElement>) => {
    onBlur?.(event);

    const container = containerRef.current;
    const nextTarget = event.relatedTarget;
    const View = container?.ownerDocument.defaultView;
    const focusRemainsInside =
      Boolean(View && nextTarget instanceof View.Node && container?.contains(nextTarget));

    if (!focusRemainsInside) onFocusChange(null);
  };

  // Pill variant: a single absolutely-positioned indicator tracks the active
  // tab's rect. The hook is null-fed when the variant doesn't use a pill, so
  // the observer is never created.
  const pillTargetValue = variant === "pill" ? value : null;
  const pillRect = useFloatingIndicator(containerRef, pillTargetValue);

  const underlineTargetValue = variant === "underline" ? value : null;
  const underlineRect = useFloatingIndicator(containerRef, underlineTargetValue);

  return (
    <div
      ref={composeRefs(containerRef, ref)}
      role="tablist"
      data-variant={variant}
      data-orientation={orientation}
      aria-orientation={orientation}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      className={cn(
        segmentedContainerVariants({ variant, orientation }),
        className,
      )}
      {...rest}
    >
      {variant === "pill" && pillRect && (
        <span
          aria-hidden="true"
          data-slot="tabs-pill"
          className={segmentedPillIndicatorClass}
          style={{ left: pillRect.left, width: pillRect.width }}
        />
      )}
      {variant === "underline" && underlineRect && (
        <span
          aria-hidden="true"
          data-slot="tabs-underline"
          className={segmentedUnderlineIndicatorClass}
          style={
            orientation === "vertical"
              ? { top: underlineRect.top, height: underlineRect.height, right: 0, width: 1 }
              : { left: underlineRect.left, width: underlineRect.width, bottom: 0, height: 1 }
          }
        />
      )}
      {children}
    </div>
  );
}

"use client";

import { type ButtonHTMLAttributes, type FocusEvent, type MouseEvent, type ReactNode, type Ref } from "react";
import { segmentedItemVariants } from "@/lib/segmented-variants";
import { cn } from "@/lib/utils";
import { getTabPanelId, getTabTriggerId, useTabsContext } from "./tabs-context";

/**
 * Bracket markers shown only when the trigger is active (variant="bracket").
 * The spans stay in the DOM at all times with `opacity-0` so the trigger's
 * measured width never changes between selected/unselected — neighbours don't
 * shift when selection moves.
 */
function BracketMarkers({ children }: { children: ReactNode }) {
  return (
    <>
      <span
        aria-hidden="true"
        className="mr-1 text-foreground opacity-0 group-data-[active=true]/segmented-item:opacity-100"
      >
        [
      </span>
      {children}
      <span
        aria-hidden="true"
        className="ml-1 text-foreground opacity-0 group-data-[active=true]/segmented-item:opacity-100"
      >
        ]
      </span>
    </>
  );
}

export interface TabsTriggerProps<TValue extends string = string>
  extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, "value" | "disabled"> {
  value: TValue;
  disabled?: boolean;
  ref?: Ref<HTMLButtonElement>;
}

/**
 * Tabs.Trigger renders a `role="tab"` button that controls a `Tabs.Content`
 * panel. It intentionally does NOT accept a `render` or `asChild` polymorphic
 * escape hatch: WAI-ARIA forbids a `tab` from navigating URLs (a tab must own
 * a tabpanel and not behave like a link). For link-based segmented navigation,
 * use `ToggleGroup.Item` instead — its `radio` / button semantics are not tied
 * to a tabpanel and can be polymorphic.
 */
export function TabsTrigger<TValue extends string = string>({
  value,
  children,
  className,
  disabled,
  ref,
  onClick,
  onFocus,
  ...rest
}: TabsTriggerProps<TValue>) {
  const {
    tabsId,
    value: selectedValue,
    tabbableValue,
    onChange,
    onFocusChange,
    panelValues,
    variant,
    size,
    orientation,
  } = useTabsContext();
  const isActive = selectedValue === value;
  const isTabbable = tabbableValue === value;
  const panelId = panelValues.includes(value) ? getTabPanelId(tabsId, value) : undefined;

  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
    if (disabled) {
      event.preventDefault();
      return;
    }

    onClick?.(event);
    if (!event.defaultPrevented) onChange(value);
  };

  const handleFocus = (event: FocusEvent<HTMLButtonElement>) => {
    onFocus?.(event);
    if (!event.defaultPrevented && !disabled) onFocusChange(value);
  };

  return (
    <button
      {...rest}
      ref={ref}
      type="button"
      id={getTabTriggerId(tabsId, value)}
      role="tab"
      aria-selected={isActive}
      aria-controls={panelId}
      aria-disabled={disabled || undefined}
      disabled={disabled}
      tabIndex={isTabbable && !disabled ? 0 : -1}
      data-diffgazer-navigation-item="tab"
      data-value={value}
      data-state={isActive ? "active" : "inactive"}
      data-active={isActive || undefined}
      data-orientation={orientation}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(
        // group/segmented-item lets the bracket markers (and any future
        // decoration) react to data-active without a separate context read.
        "group/segmented-item",
        segmentedItemVariants({ variant, size }),
        className,
      )}
    >
      {variant === "bracket" ? <BracketMarkers>{children}</BracketMarkers> : children}
    </button>
  );
}

"use client";

import { type HTMLAttributes, type Ref } from "react";
import { cn } from "@/lib/utils";
import { getTabPanelId, getTabTriggerId, useTabsContext } from "./tabs-context";

export interface TabsContentProps<TValue extends string = string>
  extends HTMLAttributes<HTMLDivElement> {
  value: TValue;
  ref?: Ref<HTMLDivElement>;
}

export function TabsContent<TValue extends string = string>({ value, children, className, ref, ...rest }: TabsContentProps<TValue>) {
  const { tabsId, value: selectedValue, orientation, triggerValues } = useTabsContext();
  const isActive = selectedValue === value;
  const triggerId = triggerValues.includes(value) ? getTabTriggerId(tabsId, value) : undefined;

  return (
    <div
      ref={ref}
      role="tabpanel"
      id={getTabPanelId(tabsId, value)}
      aria-labelledby={triggerId}
      data-state={isActive ? "active" : "inactive"}
      data-orientation={orientation}
      hidden={!isActive}
      tabIndex={isActive ? 0 : undefined}
      className={cn("mt-2 focus-visible:outline focus-visible:outline-2 focus-visible:outline-foreground focus-visible:outline-offset-2", className)}
      {...rest}
    >
      {children}
    </div>
  );
}

"use client";

import { createContext, useContext } from "react";
import type { SegmentedSize, SegmentedVariant } from "@/lib/segmented-variants";

function encodeIdPart(value: string): string {
  return encodeURIComponent(value);
}

export function getTabTriggerId(tabsId: string, value: string): string {
  return `${tabsId}-tab-${encodeIdPart(value)}`;
}

export function getTabPanelId(tabsId: string, value: string): string {
  return `${tabsId}-tabpanel-${encodeIdPart(value)}`;
}

export interface TabsContextValue {
  tabsId: string;
  value: string;
  tabbableValue: string;
  onChange: (value: string) => void;
  onFocusChange: (value: string | null) => void;
  panelValues: string[];
  triggerValues: string[];
  orientation: "horizontal" | "vertical";
  variant: SegmentedVariant;
  size: SegmentedSize;
  activationMode: "automatic" | "manual";
}

export const TabsContext = createContext<TabsContextValue | undefined>(undefined);

export function useTabsContext() {
  const context = useContext(TabsContext);
  if (!context) {
    throw new Error("Tabs compound components must be used within Tabs");
  }
  return context;
}
